mapper.select:
select gt.id, gt.gname, gt.gpicture, gt.grprice, ct.shoppingnum, ct.shoppingnum*gt.grprice smallsum
from goodstable gt, carttable ct
where gt.id=ct.goodstable_id and ct.busertable_id = #{uid}

select gt.id, gt.gname, gt.goprice, gt.grprice, gt.gpicture
from FOCUSTABLE ft, GOODSTABLE gt
where ft.goodstable_id=gt.id and ft.busertable_id = #{uid}
